const status = $input.first().json.query?.status || '';
if (status !== 'online' && status !== 'offline') {
  throw new Error('Parámetro status inválido. Usa ?status=online o ?status=offline');
}
return [{ json: { status, is_online: status === 'online' } }];

const items = $input.all();
const N8N_BASE = 'https://n8n-n8n.zzeluw.easypanel.host';

const typeLabel = { suggestion: 'Sugerencia', decision: 'Decisión requerida', directive_conflict: '⚠️ CONFLICTO DE DIRECTIVA' };
const agentLabel = (a) => a.replace('agent_', '').replace('util_', '').replace(/_/g, ' ');

let rows = '';
items.forEach((item, i) => {
  const c = item.json;
  const answerUrl = `${N8N_BASE}/webhook/consultation-answer?id=${c.id}&answer=yes`;
  const rejectUrl = `${N8N_BASE}/webhook/consultation-answer?id=${c.id}&answer=no`;
  const badge = c.consultation_type === 'directive_conflict'
    ? 'background:#e74c3c;color:white'
    : c.consultation_type === 'decision'
      ? 'background:#e67e22;color:white'
      : 'background:#3498db;color:white';
  rows += `
    <tr style="border-bottom:1px solid #eee;">
      <td style="padding:12px 8px;">
        <span style="${badge};padding:3px 8px;border-radius:12px;font-size:11px;font-weight:bold;">${typeLabel[c.consultation_type]}</span>
      </td>
      <td style="padding:12px 8px;color:#7f8c8d;font-size:13px;">[${agentLabel(c.agent_name)}]</td>
      <td style="padding:12px 8px;">${c.message}</td>
      <td style="padding:12px 8px;white-space:nowrap;">
        <a href="${answerUrl}" style="background:#27ae60;color:white;padding:6px 14px;text-decoration:none;border-radius:4px;font-size:13px;margin-right:6px;">Sí</a>
        <a href="${rejectUrl}" style="background:#e74c3c;color:white;padding:6px 14px;text-decoration:none;border-radius:4px;font-size:13px;">No</a>
      </td>
    </tr>`;
});

const htmlBody = `
  <div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;">
    <h2 style="color:#2c3e50;">Studio AI — Consultas pendientes</h2>
    <p>Tienes <strong>${items.length} consulta${items.length !== 1 ? 's' : ''}</strong> de los agentes esperando tu respuesta:</p>
    <table style="width:100%;border-collapse:collapse;">
      <thead><tr style="background:#f8f9fa;">
        <th style="padding:10px 8px;text-align:left;">Tipo</th>
        <th style="padding:10px 8px;text-align:left;">Agente</th>
        <th style="padding:10px 8px;text-align:left;">Consulta</th>
        <th style="padding:10px 8px;text-align:left;">Respuesta</th>
      </tr></thead>
      <tbody>${rows}</tbody>
    </table>
    <p style="color:#95a5a6;font-size:12px;margin-top:20px;">Sistema multiagente — ${new Date().toLocaleString('es-ES')}</p>
  </div>`;

return [{ json: { html_body: htmlBody, count: items.length } }];
